module top_module(in0, in1, invalid_out);input in0;
input in1;
output reg [1:0] invalid_out;

always @ (in0, in1) begin
    if (in0 && !in1) // in0 is high and in1 is low
        invalid_out <= 2'b01;
    else if (!in0 && in1) // in0 is low and in1 is high
        invalid_out <= 2'b10;
    else if (in0 && in1) // both inputs are high
        invalid_out <= 2'b10;
    else // both inputs are low
        invalid_out <= 2'b00;
end

endmodule
